:struct<Stack> {
    :list<:int> data;
    :int top;
};

!func make_stack() -> :struct<Stack> {
    :struct<Stack> s;
    s::data = [];
    s::top = -1;
    !return s;
}

!func push(:struct<Stack> s, :int v) -> :void {
    append(s::data, v);
    s::top = s::top + 1;
}

!func stack_pop(:struct<Stack> s) -> :int {
    !if (s::top < 0) { !return -1; }
    :int val = s::data[s::top];
    s::top = s::top - 1;
    !return val;
}

:struct<Queue> {
    :list<:int> data;
    :int head;
    :int tail;
};

!func make_queue() -> :struct<Queue> {
    :struct<Queue> q;
    q::data = [];
    q::head = 0;
    q::tail = 0;
    !return q;
}

!func enqueue(:struct<Queue> q, :int v) -> :void {
    append(q::data, v);
    q::tail = q::tail + 1;
}

!func dequeue(:struct<Queue> q) -> :int {
    !if (q::head >= q::tail) { !return -1; }
    :int val = q::data[q::head];
    q::head = q::head + 1;
    !return val;
}

:struct<BSTNode> {
    :int value;
    :int left;
    :int right;
};

!func insert(:int val, :list<:struct<BSTNode>> nodes, :int root) -> :void {
    :int cur = root;
    !for (:int i, 0, 1000, 1) {
        :struct<BSTNode> n = nodes[cur];
        !if (val < n::value) {
            !if (n::left == -1) { n::left = val; !break; }
            cur = n::left;
        } !else {
            !if (n::right == -1) { n::right = val; !break; }
            cur = n::right;
        }
    }
}

!func bubble_sort(:list<:int> arr) -> :void {
    :int n = len(arr);

    !for (:int i, 0, n, 1) {
        !for (:int j, 0, n - i - 1, 1) {
            !if (arr[j] > arr[j + 1]) {
                :int tmp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = tmp;
            }
        }
    }
}

!func merge(:list<:int> a, :list<:int> b) -> :list<:int> {
    :list<:int> result = [];
    :int i = 0;
    :int j = 0;

    !while (i < len(a) !and j < len(b)) {
        !if (a[i] <= b[j]) {
            append(result, a[i]);
            i = i + 1;
        } !else {
            append(result, b[j]);
            j = j + 1;
        }
    }

    !while (i < len(a)) {
        append(result, a[i]);
        i = i + 1;
    }

    !while (j < len(b)) {
        append(result, b[j]);
        j = j + 1;
    }

    !return result;
}

